{
  "name": "xananode-hugo",
  "version": "0.1.0",
  "private": true,
  "license": "Apache-2.0",
  "type": "module",
  "scripts": {
    "build:substrate-source": "node tools/build-substrate-source.mjs",
    "prepare": "node tools/prepare-xananode.mjs exampleSite",
    "validate": "node tools/prepare-xananode.mjs exampleSite",
    "example:dev": "npm run prepare && hugo server --source exampleSite --themesDir ../..",
    "example:build": "npm run prepare && hugo --source exampleSite --themesDir ../.. --gc --cleanDestinationDir --minify",
    "core:init": "git submodule update --init --recursive vendor/xananode-core",
    "core:update": "git submodule update --init --remote --merge --recursive vendor/xananode-core",
    "core:status": "git submodule status --recursive vendor/xananode-core"
  },
  "dependencies": {
    "@xananode/core": "file:./vendor/xananode-core"
  },
  "devDependencies": {
    "ajv": "^8.17.1",
    "gray-matter": "^4.0.3",
    "glob": "^11.0.0"
  }
}
